public void testAddNullArrayNonNullElement() {
    String[] stringArray = null;
    String aString = "test";
    String[] result = ArrayUtils.add(stringArray, aString);
    assertNotNull(result);
    assertEquals(1, result.length);
    assertEquals("test", result[0]);
}

public void testAddWithIndexNullArrayNonNullElement() {
    Integer[] intArray = null;
    Integer element = 42;
    Integer[] result = ArrayUtils.add(intArray, 0, element);
    assertNotNull(result);
    assertEquals(1, result.length);
    assertEquals(Integer.valueOf(42), result[0]);
}

public void testAddNonNullArrayNullElement() {
    String[] stringArray = new String[]{"existing"};
    String aString = null;
    String[] result = ArrayUtils.add(stringArray, aString);
    assertNotNull(result);
    assertEquals(2, result.length);
    assertEquals("existing", result[0]);
    assertNull(result[1]);
}
